  automaNextBlock();
})();

(async () => {
  const aiName = "Reka Chat";
  const originalPrompt = automaRefData('variables', 'originalPrompt') || '';
  function cleanText(raw) {
    let text = String(raw || '').replace(/\r/g, '\n');
    const uiExact = new Set([
      'Edge','Research','Chat','Speech','New Chat','Sign In','PROMPT TYPE','Clear',
      'Image analysis','Code analysis','Multilingual chat','API Documentation','API Platform','Talk to Sales',
      'Responses may be inaccurate. Verify important information.','Pro','Free preview of advanced search enabled.',
      'Home','Discover','Spaces','Library','Upgrade','Try Pro','Attach','Voice','Send','Submit','Stop generating',
      'Regenerate','Share','Copy','Copied','Like','Dislike','Sources','Related','Ask follow-up','Search',
      'Terms','Privacy','Help','Settings','Account','Log in','Login','Sign up','Get app','Apps'
    ]);
    let lines = text.split(/\n+/).map(s => s.trim()).filter(Boolean);
    lines = lines.filter(line => !uiExact.has(line));
    text = lines.join('\n');
    const endMarker = '----- END PREVIOUS CONVERSATION -----';
    const idx = text.lastIndexOf(endMarker);
    if (idx >= 0) text = text.slice(idx + endMarker.length);
    const beginMarker = '----- BEGIN PREVIOUS CONVERSATION -----';
    const idx2 = text.lastIndexOf(beginMarker);
    if (idx2 >= 0) text = text.slice(idx2 + beginMarker.length);
    text = text
      .replace(/^Hi\s+[^,]+,?/i, '')
      .replace(/The following is the original prompt[\s\S]{0,1200}?discussion\./i, '')
      .replace(/Please do not simply summarize[\s\S]{0,1200}?where appropriate\./i, '')
      .replace(/Treat this as collaborative peer review[\s\S]{0,500}?discussion\./i, '')
      .replace(/={5,}\s*(ORIGINAL PROMPT|REKA CHAT|REKA|PERPLEXITY|COPILOT|GROK|GEMINI|DEEPSEEK|CLAUDE|CHATGPT)\s*={5,}/ig, '')
      .trim();
    if (originalPrompt) {
      text = text.replace(originalPrompt, '').trim();
    }
    text = text.replace(/\n{3,}/g, '\n\n').trim();
    return text;
  }
  const raw = document.body ? document.body.innerText : '';
  let latest = cleanText(raw);
  if (!latest) latest = '[No clean response text was detected. Full page copy may be needed here.]';
  let transcript = automaRefData('variables', 'roundtableTranscript') || '';
  if (!transcript) {
    transcript = `====================\nORIGINAL PROMPT\n====================\n\n${originalPrompt || '[Original prompt not captured]'}\n`;
  }
  transcript += `\n\n====================\n${aiName}\n====================\n\n${latest}\n`;
  automaSetVariable('latestResponse', latest);
  automaSetVariable('roundtableTranscript', transcript);
  try { await navigator.clipboard.writeText(transcript); } catch(e) {}
  automaNextBlock();
})();

(async () => {
  const currentAI = "Perplexity";
  const previousAI = "Reka Chat";
  const nextAI = "Copilot";
  const transcript = automaRefData('variables', 'roundtableTranscript') || '';
  const prompt = `Hi ${currentAI},

The following is an ongoing AI roundtable discussion. The original prompt and all previous AI contributions are included below.

Please do not simply summarize or agree. Instead:

- Evaluate the accuracy and reasoning so far.
- Point out errors, omissions, weak assumptions, or unsupported claims.
- Add missing knowledge, perspectives, or evidence.
- Challenge conclusions you disagree with and explain why.
- Expand upon strong ideas.
- Suggest better approaches or alternatives where appropriate.
- Avoid repeating points already made unless you are refining or correcting them.

Your complete response will be appended to the transcript${nextAI ? ` and forwarded to ${nextAI}` : ''}.

----- BEGIN ROUNDTABLE TRANSCRIPT -----

${transcript}

----- END ROUNDTABLE TRANSCRIPT -----`;

  function visible(el) {
    const r = el.getBoundingClientRect();
    const s = getComputedStyle(el);
    return r.width > 80 && r.height > 15 && s.visibility !== 'hidden' && s.display !== 'none' && !el.disabled;
  }
  function setNativeValue(el, value) {
    const proto = Object.getPrototypeOf(el);
    const desc = Object.getOwnPropertyDescriptor(proto, 'value');
    if (desc && desc.set) desc.set.call(el, value); else el.value = value;
    el.dispatchEvent(new Event('input', { bubbles: true }));
    el.dispatchEvent(new Event('change', { bubbles: true }));
  }
  const candidates = [...document.querySelectorAll('textarea, div[contenteditable="true"], [role="textbox"], input[type="text"], input:not([type])')]
    .filter(visible)
    .sort((a,b) => b.getBoundingClientRect().bottom - a.getBoundingClientRect().bottom);
