  if (!promptBox) throw new Error('Could not find prompt box on ' + currentAI);
  promptBox.focus();
  if (promptBox.isContentEditable || promptBox.getAttribute('contenteditable') === 'true') {
    document.execCommand('selectAll', false, null);
    document.execCommand('insertText', false, prompt);
  } else {
    setNativeValue(promptBox, prompt);
  }
  automaNextBlock();
})();

(() => {
  function visible(el) {
    const r = el.getBoundingClientRect();
    const s = getComputedStyle(el);
    return r.width > 0 && r.height > 0 && s.visibility !== 'hidden' && s.display !== 'none';
  }
  const labels = ['submit', 'send', 'ask', 'arrow'];
  const buttons = [...document.querySelectorAll('button, [role="button"]')].filter(visible);
  let btn = buttons.find(b => {
    const text = (b.innerText || '').toLowerCase();
    const aria = (b.getAttribute('aria-label') || '').toLowerCase();
    const title = (b.getAttribute('title') || '').toLowerCase();
    const combined = `${text} ${aria} ${title}`;
    return labels.some(x => combined.includes(x)) && !b.disabled && b.getAttribute('aria-disabled') !== 'true';
  });
  if (!btn) {
    btn = buttons.filter(b => !b.disabled && b.getAttribute('aria-disabled') !== 'true')
      .sort((a, b) => {
        const ar = a.getBoundingClientRect();
        const br = b.getBoundingClientRect();
        return (br.bottom - ar.bottom) || (br.right - ar.right);
      })[0];
  }
  if (btn) btn.click();
  else {
    const active = document.activeElement;
    active && active.dispatchEvent(new KeyboardEvent('keydown', {key:'Enter', code:'Enter', bubbles:true, cancelable:true}));
  }
  automaNextBlock();
})();

